//물류/공통(통합)/매입요율/노임/노조/분회/반 등록

// 임시 메뉴 ID
scwin.tempMenuID = 0;
// 현재 로우 위치
scwin.currRow = 0;
scwin.oldRow = 0;
// valid 여부
scwin.isValid = false;
scwin.hid_tvIndex = 2;

scwin.onpageload = function() {

};

//-------------------------------------------------------------------------
// scwin.name : f_OnLoad
// scwin.desc : 화면로딩시
//-------------------------------------------------------------------------
scwin.f_OnLoad = function() {
    scwin.f_setHeaderInspection();
    scwin.f_Retrieve();

    ds_Inspection.set("lunionOrgCd", ds_unionOrgnizationTreeView.getCellData(1 , "lunionOrgCd"));
    ds_Inspection.set("lvl", 1);
    scwin.f_detailRetrieve();

    $c.gus.cfDisableObjects([ed_lunionOrgCd,ed_lunionOrgCd01]);
    rd_lunionCls01.setDisabled(true);

    //rd_lunionCls01.Enable = "false";
};

scwin.f_setLunionCls = function () {
    $c.sbm.setAction(sbm_lunionCls, "/cm.zz.RetrieveComboCMD.do?sysCd=DsCommonEBC&queryId=retriveUnionOrganizationCd");
    $c.sbm.execute(sbm_lunionCls);

    //var vLunionCls = $c.gus.gauceUtil("getLuxeComboData","DsCommonEBC","retriveUnionOrganizationCd",[""]);  이거안됨.
    //ds_lunionCls.setJSON(vLunionCls, false);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
