scwin.tv_unionOrgnizationTree_onclick = async function () {
//console.log('scwin.tv_unionOrgnizationTree_onclick~~');
//console.log(info);
    //index,label,value
    //var index = info.newNode.index-1;

    //console.log('index =>'+tv_unionOrgnizationTree.getSelectedIndex());;

    //var index = ds_unionOrgnizationTreeView.getRowPosition();
    var index = tv_unionOrgnizationTree.getSelectedIndex() - 1;       //1,2,3,...

//console.log("rowpos ==>"+index);

    if( index > 0 ) {
        ds_Inspection.set("lunionOrgCd", ds_unionOrgnizationTreeView.getCellData(index , "lunionOrgCd")) ;
        ds_Inspection.set("lvl", ds_unionOrgnizationTreeView.getCellData(index , "lvl" )) ;

        var check = ds_unionOrgnizationTreeView.getCellData(index , "lunionOrgCd" );
        var lvl = ds_unionOrgnizationTreeView.getCellData(index , "lvl");

        //var status = ds_unionOrgnizationTree.SysStatus(ds_unionOrgnizationTree.RowPosition);
        var status = ds_unionOrgnizationTreeView.getRowStatus(index);

//console.log("status ==>"+status);
//console.log("lvl ==>"+lvl);
//console.log("scwin.isValid ==>"+scwin.isValid);

        //if(scwin.isValid == true && status == 0 ) {
        if(scwin.isValid == true && status == "R" ) {
            if(lvl == 1 ) {
                await $c.gus.cfValidate([tbl_menuInfo]);
            } else if( lvl == 2 || lvl == 3 ) {
                await $c.gus.cfValidate([tbl_menuInfo01]);
            }

            //ds_unionOrgnizationTreeView.setRowPosition(scwin.oldRow);
            lvl = 0;
            return;
        }

        if(check.length > 0) {
            scwin.f_detailRetrieve();
            $c.gus.cfEnableObjects([tbl_menuInfo]);
            $c.gus.cfEnableObjects([tbl_menuInfo01]);
            $c.gus.cfDisableObjects([ed_lunionOrgCd,ed_lunionOrgCd01]);
            rd_lunionCls01.setDisabled(true);
            //rd_lunionCls01.Enable = "false";
        }

        ds_Inspection.set("lunionOrgCd", "");
        ds_Inspection.set("lvl", 0);

        //ds_unionOrgnizationTreeView.setRowPosition(index);
    }
};
